const data = $input.item.json;
const flowSteps = data.flow_steps;
const currentStep = flowSteps.find(s => s.order === data.step_order);

if (!currentStep) {
  throw new Error(`Step ${data.step_order} não encontrado`);
}

const variables = data.context || {};

variables.first_name = variables.first_name || data.first_name || "Cliente";
variables.full_name = variables.full_name || data.full_name || "";
variables.email = variables.email || data.email || "";

function replaceVariables(text, vars) {
  if (!text) return '';
  let result = text;
  Object.keys(vars).forEach(key => {
    const regex = new RegExp(`\\{\\{\\s*${key}\\s*\\}\\}`, 'g');
    result = result.replace(regex, vars[key] || '');
  });
  return result;
}

if (!data.phone) throw new Error('Phone obrigatório');

const hasMultipleMessages = currentStep.messages && Array.isArray(currentStep.messages);

if (hasMultipleMessages) {
  const formattedMessages = currentStep.messages.map(msg => {
    let messageText = '';
    if (msg.type === 'text') {
      messageText = replaceVariables(msg.content, variables);
    } else {
      messageText = replaceVariables(msg.caption || '', variables);
    }

    return {
      step_id: data.step_id,
      flow_id: data.flow_id,
      lead_id: data.lead_id,
      phone: data.phone.replace(/\D/g, ''),
      message_type: msg.type,
      message_text: messageText,
      media_url: msg.media_url || null,
      flow_code: data.flow_code,
      step_order: data.step_order
    };
  });

  return formattedMessages.map(msg => ({ json: msg }));

} else {
  let messageText = '';
  if (currentStep.message_type === 'text') {
    messageText = replaceVariables(currentStep.content, variables);
  } else {
    messageText = replaceVariables(currentStep.caption || '', variables);
  }

  return {
    json: {
      step_id: data.step_id,
      flow_id: data.flow_id,
      lead_id: data.lead_id,
      phone: data.phone.replace(/\D/g, ''),
      message_type: currentStep.message_type,
      message_text: messageText,
      media_url: currentStep.media_url || null,
      flow_code: data.flow_code,
      step_order: data.step_order
    }
  };
}

// 1. CAPTURA DOS DADOS
const item = $input.item.json;
const zapResolved = item._whatsapp_resolved || {};
const rawData = item.body || item.data || item; 

// O nó anterior ("Resolve Lid e Jid") já fez o trabalho duro. Vamos confiar nele!
// Ele já entrega o LID ou o número formatado perfeitamente.
let activeIdentifier = zapResolved.jid || zapResolved.lid || zapResolved.identificador_ativo || rawData.phone || "";

// Garantia extra caso o número venha limpo sem o sufixo do WhatsApp
if (!activeIdentifier.includes('@')) {
    let cleanNumber = String(activeIdentifier).replace(/\D/g, '');
    if (cleanNumber && !cleanNumber.startsWith('55')) {
        cleanNumber = '55' + cleanNumber;
    }
    activeIdentifier = cleanNumber; 
}

// 2. CAPTURA DE TIPO E MÍDIA
let messageType = (rawData.message_type || "text").toLowerCase();
let mediaUrl = rawData.media_url || null;
let caption = rawData.message_text || "";

// 🛡️ TRAVA DE SEGURANÇA 1: Se for envio de ficheiro/mídia mas a URL vier nula ou vazia, converte para texto!
if (messageType !== 'text' && (!mediaUrl || mediaUrl.trim() === "")) {
    messageType = 'text';
}

// 🛡️ TRAVA DE SEGURANÇA 2: Se for texto e estiver totalmente vazio, coloca um espaço invisível.
// A API do WhatsApp bloqueia envios com "Body" vazio.
if (messageType === 'text' && (!caption || caption.trim() === "")) {
    caption = " "; 
}

// 3. EXTRAÇÃO INTELIGENTE DE MIME TYPE (Mais robusta)
const getMimeType = (url, type) => {
  if (!url) return type === 'audio' ? 'audio/ogg' : 'application/octet-stream';

  // 🛡️ TRAVA DE SEGURANÇA 3: Procura a extensão de forma segura. Se o link não tiver (ex: Google Drive), assume um padrão seguro.
  const extMatch = url.match(/\.([a-zA-Z0-9]+)(?:[\?#]|$)/);
  const ext = extMatch ? extMatch[1].toLowerCase() : null;

  const map = { 
    'mp3': 'audio/mpeg', 'ogg': 'audio/ogg', 'wav': 'audio/wav',
    'jpg': 'image/jpeg', 'jpeg': 'image/jpeg', 'png': 'image/png',
    'mp4': 'video/mp4', 'pdf': 'application/pdf'
  };

  return map[ext] || (
      type === 'image' ? 'image/jpeg' : 
      type === 'video' ? 'video/mp4' : 
      type === 'audio' ? 'audio/ogg' : 'application/octet-stream'
  );
};

// 4. MONTAGEM DINÂMICA DO PAYLOAD (DinastiAPI)
let endpoint = `/chat/send/${messageType}`;
let payload = { 
    Phone: activeIdentifier,
    NumberCheck: true
};

if (messageType === 'text') {
    payload.Body = caption;
} else if (messageType === 'audio') {
    payload.Audio = mediaUrl;
    payload.MimeType = getMimeType(mediaUrl, 'audio');
} else {
    // Formatação para Image, Video, Document
    const typeKey = messageType.charAt(0).toUpperCase() + messageType.slice(1);
    payload[typeKey] = mediaUrl;

    // Só envia legenda se ela realmente existir
    if (caption.trim() !== "") {
        payload.Caption = caption;
    }
    payload.MimeType = getMimeType(mediaUrl, messageType);
}

// 5. RESPOSTA COM METADADOS
return {
  json: {
    endpoint_suffix: endpoint,
    payload: payload,
    _metadata: {
        original_id: zapResolved.jid || zapResolved.lid || zapResolved.identificador_ativo || rawData.phone,
        final_id: activeIdentifier,
        message_type: messageType,
        timestamp: new Date().toISOString()
    }
  }
};

// Recupera o número do input anterior
const phone = $('Endpoint').first().json.payload.Phone;

// Remove qualquer caractere que não seja número (parênteses, espaços, traços)
let cleanPhone = phone.toString().replace(/\D/g, '');

// Verifica se o número começa com o DDI do Brasil (55)
// Se não tiver, podemos assumir que é brasileiro para a lógica de normalização
let hasDDI = cleanPhone.startsWith('55');
let coreNumber = hasDDI ? cleanPhone.substring(2) : cleanPhone;

// A lógica foca no coreNumber (DDD + Número)
// No Brasil, o coreNumber tem 10 dígitos (sem o 9) ou 11 dígitos (com o 9)
let ddd = coreNumber.substring(0, 2);
let rest = coreNumber.substring(2);

let processedNumber = "";

if (rest.length === 9 && rest.startsWith('9')) {
    // Caso 1: Tem o 9 adicional -> REMOVER o 9
    processedNumber = ddd + rest.substring(1);
} else if (rest.length === 8) {
    // Caso 2: Não tem o 9 adicional -> ADICIONAR o 9
    processedNumber = ddd + '9' + rest;
} else {
    // Caso 3: Formato desconhecido (ex: fixo ou erro) -> Mantém o original limpo
    processedNumber = coreNumber;
}

// Remonta com o DDI 55
const finalPhone = "55" + processedNumber;

return {
  normalizedPhone: finalPhone,
  originalPhone: phone
};

