const tentar = async (phone) => {
  const res = await this.helpers.request({
    method: 'POST',
    uri: `${API_URL}${endpoint}`,
    headers: { 'token': TOKEN, 'Content-Type': 'application/json' },
    body: { ...payload, Phone: phone },
    json: true
  });

  // 🛡️ API retorna 200 mas com success: false em caso de erro — trata como falha
  if (!res || res.success === false) {
    throw new Error(res?.error || 'Resposta inválida da API');
  }

  return res;
};

let resultado = null;
let usou = null;
let erroLid = null;
let erroJid = null;

// Tentativa 1: LID
if (lid) {
  try {
    resultado = await tentar(lid);
    usou = 'lid';
  } catch (e) {
    erroLid = e.message;
  }
}

// Tentativa 2: JID (se LID falhou ou não existe)
if (!resultado && jid) {
  try {
    resultado = await tentar(jid);
    usou = 'jid';
  } catch (e) {
    erroJid = e.message;
  }
}

// Se ambos falharam → joga erro pro output de erro
if (!resultado) {
  throw new Error(`Falha LID: ${erroLid} | Falha JID: ${erroJid}`);
}

return {
  json: {
    ...endpointData,
    _send_result: resultado,
    _used_identifier: usou
  }
};
